mapper.update:
UPDATE sm_token_wallet
SET balance = balance + #{amount}, updated_at = NOW()
WHERE member_id = #{memberId} AND ym = #{ym}

mapper.select:
SELECT id, type, amount, balance_after AS balanceAfter, description,
       project_id AS projectId, expires_at AS expiresAt, created_at AS createdAt
FROM sm_token_ledger
WHERE member_id = #{memberId}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}
